MOD = 1000000007

def mod_inv(x, mod):
    return pow(x, mod - 2, mod)

def solve():
    import sys
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    results = []

    max_n = 0
    test_cases = []

    for i in range(1, t + 1):
        n = int(data[i])
        test_cases.append(n)
        if n > max_n:
            max_n = n

    # Precompute factorials and inverse factorials
    fact = [1] * (2 * max_n + 1)
    inv_fact = [1] * (2 * max_n + 1)

    for i in range(2, 2 * max_n + 1):
        fact[i] = fact[i - 1] * i % MOD

    inv_fact[2 * max_n] = mod_inv(fact[2 * max_n], MOD)

    for i in range(2 * max_n - 1, 0, -1):
        inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD

    for n in test_cases:
        # Calculate (2n choose n) * n! % MOD
        result = fact[2 * n] * inv_fact[n] % MOD * inv_fact[n] % MOD * fact[n] % MOD
        results.append(result)

    for res in results:
        print(res)

