import sys
import math

def precompute_c(n):
    c = [[0] * (n + 1) for _ in range(n + 1)]
    for l in range(1, n + 1):
        for r in range(l, n + 1):
            count = 0
            for i in range(l, r + 1):
                for j in range(i, r + 1):
                    if math.gcd(i, j) >= l:
                        count += 1
            c[l][r] = count
    return c

def solve():
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    index = 1
    results = []

    for _ in range(t):
        n = int(data[index])
        k = int(data[index + 1])
        index += 2

        # Precompute c(l, r) for the given n
        c = precompute_c(n)

        # DP array to store minimum sum
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(1, k + 1):
            new_dp = [float('inf')] * (n + 1)
            for j in range(i, n + 1):
                for x in range(i - 1, j):
                    new_dp[j] = min(new_dp[j], dp[x] + c[x + 1][j])
            dp = new_dp

        results.append(dp[n])

    sys.stdout.write('\n'.join(map(str, results)) + '\n')

