    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    results = []

    for case_index in range(1, t + 1):
        s = data[case_index]
        ab_count = 0
        ba_count = 0

        # Count occurrences of "ab" and "ba"
        for i in range(len(s) - 1):
            if s[i:i+2] == "ab":
                ab_count += 1
            elif s[i:i+2] == "ba":
                ba_count += 1

        # If counts are equal, no change is needed
        if ab_count == ba_count:
            results.append(s)
        else:
            # Make minimal change to balance
            if ab_count > ba_count:
                # Change the first "ab" to "aa" or "bb"
                for i in range(len(s) - 1):
                    if s[i:i+2] == "ab":
                        s = s[:i] + "aa" + s[i+2:]
                        break
            else:
                # Change the first "ba" to "aa" or "bb"
                for i in range(len(s) - 1):
                    if s[i:i+2] == "ba":
                        s = s[:i] + "bb" + s[i+2:]
                        break
            results.append(s)

    for result in results:
        print(result)

