    results = []

    for case in range(1, t + 1):
        s = data[case]
        n = len(s)

        # We will use a coloring approach to check bipartiteness
        color = [-1] * n  # -1 means uncolored, 0 and 1 are the two colors

        def bfs(start):
            queue = [start]
            color[start] = 0  # Start coloring with 0

            while queue:
                node = queue.pop(0)
                for i in range(n):
                    if i == node:
                        continue
                    if s[node] == 'E' and s[i] == 'E':
                        if color[i] == -1:
                            color[i] = color[node]
                            queue.append(i)
                        elif color[i] != color[node]:
                            return False
                    elif s[node] == 'N' and s[i] == 'N':
                        if color[i] == -1:
                            color[i] = 1 - color[node]
                            queue.append(i)
                        elif color[i] == color[node]:
                            return False
            return True

        possible = True
        for i in range(n):
            if color[i] == -1:
                if not bfs(i):
                    possible = False
                    break

        if possible:
            results.append("YES")
